const raw = $input.first().json;
const msg = raw.message;
const chatId = msg?.chat?.id;
const userText = typeof msg?.text === "string" ? msg.text.trim() : "";
const hasText = userText.length > 0;
return [{
  json: {
    rqUid: $execution.id,
    chatId,
    userText,
    hasText
  }
}];

const prep = $("02 Prepare Input").first().json;
const config = $("04 Load Config").first().json;
const oauth = $input.first().json;
const token = oauth.access_token;
if (!token) {
  return [{
    json: {
      error: true,
      chatId: prep.chatId,
      oauthResponse: oauth
    }
  }];
}
const fullPrompt = config.system_prompt + "\n\nБАЗА ЗНАНИЙ:\n" + config.faq;
return [{
  json: {
    error: false,
    chatId: prep.chatId,
    access_token: token,
    gigachatPayload: {
      model: config.model,
      messages: [
        { role: "system", content: fullPrompt },
        { role: "user", content: prep.userText }
      ],
      temperature: 0.2,
      max_tokens: 1200,
      stream: false,
      function_call: "none"
    }
  }
}];

const prep = $("02 Prepare Input").first().json;
const gigachat = $input.first().json;
const aiText = gigachat.choices?.[0]?.message?.content || "Извините, не удалось получить ответ.";
return [{
  json: {
    chatId: prep.chatId,
    aiText
  }
}];
